15	//! Logging infrastructure — severity-named macros with auto file/line capture.
16	//!
17	//! All application logging goes through `apcrl_*_now!`, `apcrl_*_if!`, and
18	//! comparison variants. No naked `println!`/`eprintln!` elsewhere in the codebase.
19	//!
20	//! Output is line-oriented to stdout. Format:
21	//!   `[LEVEL] [YYYY-MM-DD HH:MM:SS.mmm] [file:line] message`
22	//!
23	//! The timestamp is local wall-clock with millisecond precision, captured at
24	//! emit time by `chrono::Local::now()`. Level, timestamp, and file:line flow
25	//! through a single formatter so stdout and the tee sink never drift.
26	//!
27	//! An optional file-tee sink can be installed via `apcrl_tee_init` once at
28	//! application startup. When present, every emission is appended to the tee
29	//! file in the exact format that goes to stdout — one format, two sinks. Tee
30	//! write failures are swallowed to avoid recursive-logging hazards; stdout
31	//! remains authoritative.
32	//!
33	//! Suffix families:
34	//!   `_now`  — unconditional emission
35	//!   `_if`   — boolean conditional, returns the bool
36	//!   `_eq`, `_ne`, `_lt`, `_gt`, `_le`, `_ge` — comparison conditional,
37	//!            stringifies arguments, returns the bool
38	
39	use std::fs::{File, OpenOptions};
40	use std::io::Write;
41	use std::path::Path;
42	use std::sync::{Mutex, OnceLock};
43	
44	pub const APCRL_LEVEL_TRACE: &str = "[TRACE]";
45	pub const APCRL_LEVEL_INFO:  &str = "[INFO]";
46	pub const APCRL_LEVEL_ERROR: &str = "[ERROR]";
47	pub const APCRL_LEVEL_FATAL: &str = "[FATAL]";
48	
49	static ZAPCRL_TEE: OnceLock<Mutex<File>> = OnceLock::new();
50	
51	/// Install a file-tee sink. Every subsequent `apcrl_*` emission is appended
52	/// to `path` in the exact format that goes to stdout. The file is opened in
53	/// append-create mode. Call once from application startup; subsequent calls
54	/// return `Err` without disturbing the active sink.
55	pub fn apcrl_tee_init(path: &Path) -> Result<(), String> {
56	    let file = OpenOptions::new()
57	        .create(true)
58	        .append(true)
59	        .open(path)
60	        .map_err(|e| format!("open tee file {}: {}", path.display(), e))?;
61	    ZAPCRL_TEE.set(Mutex::new(file))
62	        .map_err(|_| "tee already initialized".to_string())?;
63	    Ok(())
64	}
65	
66	fn zapcrl_tee_write(line: &str) {
67	    if let Some(mtx) = ZAPCRL_TEE.get() {
68	        if let Ok(mut f) = mtx.lock() {
69	            let _ = writeln!(f, "{}", line);
70	            let _ = f.flush();
71	        }
72	    }
73	}
74	
75	fn zapcrl_format(level: &str, file: &str, line: u32, msg: &str) -> String {
76	    let ts = chrono::Local::now().format("%Y-%m-%d %H:%M:%S%.3f");
77	    format!("{} [{}] [{}:{}] {}", level, ts, file, line, msg)
78	}
79	
80	#[doc(hidden)]
81	pub fn zapcrl_emit(level: &str, file: &str, line: u32, msg: &str) {
82	    let formatted = zapcrl_format(level, file, line, msg);
83	    println!("{}", formatted);
84	    zapcrl_tee_write(&formatted);
85	}
86	
87	#[doc(hidden)]
88	pub fn zapcrl_emit_fatal(file: &str, line: u32, msg: &str) -> ! {
89	    let formatted = zapcrl_format(APCRL_LEVEL_FATAL, file, line, msg);
90	    println!("{}", formatted);
91	    zapcrl_tee_write(&formatted);
92	    std::process::exit(1);
93	}
94	
95	// ============================================================
96	// Unconditional (_now)
97	// ============================================================
98	
99	#[macro_export] macro_rules! apcrl_trace_now {
100	    ($($arg:tt)*) => { $crate::apcrl_log::zapcrl_emit($crate::apcrl_log::APCRL_LEVEL_TRACE, file!(), line!(), &format!($($arg)*)) };
101	}
102	#[macro_export] macro_rules! apcrl_info_now {
103	    ($($arg:tt)*) => { $crate::apcrl_log::zapcrl_emit($crate::apcrl_log::APCRL_LEVEL_INFO, file!(), line!(), &format!($($arg)*)) };
104	}
105	#[macro_export] macro_rules! apcrl_error_now {
106	    ($($arg:tt)*) => { $crate::apcrl_log::zapcrl_emit($crate::apcrl_log::APCRL_LEVEL_ERROR, file!(), line!(), &format!($($arg)*)) };
107	}
108	#[macro_export] macro_rules! apcrl_fatal_now {
109	    ($($arg:tt)*) => { $crate::apcrl_log::zapcrl_emit_fatal(file!(), line!(), &format!($($arg)*)) };
110	}
111	
112	// ============================================================
113	// Boolean conditional (_if)
114	// ============================================================
115	
116	#[macro_export] macro_rules! apcrl_trace_if {
117	    ($cond:expr, $($arg:tt)*) => {{ let z = $cond; if z { $crate::apcrl_log::zapcrl_emit($crate::apcrl_log::APCRL_LEVEL_TRACE, file!(), line!(), &format!($($arg)*)); } z }};
118	}
119	#[macro_export] macro_rules! apcrl_error_if {
120	    ($cond:expr, $($arg:tt)*) => {{ let z = $cond; if z { $crate::apcrl_log::zapcrl_emit($crate::apcrl_log::APCRL_LEVEL_ERROR, file!(), line!(), &format!($($arg)*)); } z }};
121	}
122	#[macro_export] macro_rules! apcrl_fatal_if {
123	    ($cond:expr, $($arg:tt)*) => { if $cond { $crate::apcrl_log::zapcrl_emit_fatal(file!(), line!(), &format!($($arg)*)); } };
124	}
125	
126	// ============================================================
127	// Trace comparison variants
128	// ============================================================
