// Unconditional (_now)
// ============================================================

#[macro_export] macro_rules! apcrl_trace_now {
    ($($arg:tt)*) => { $crate::apcrl_log::zapcrl_emit($crate::apcrl_log::APCRL_LEVEL_TRACE, file!(), line!(), &format!($($arg)*)) };
