29	use std::path::PathBuf;
30	use std::process::ExitCode;
31	
32	use rbtd::rbtdrc_crucible::{
33	    rbtdrc_lookup_fixture, rbtdrc_set_context, rbtdrc_take_context, RBTDRC_FIXTURES,
34	};
35	use rbtd::rbtdre_engine::{
36	    rbtdre_detect_colors, rbtdre_find_case, rbtdre_list_cases, rbtdre_print_summary,
37	    rbtdre_run_fixture, rbtdre_run_single_case,
38	};
39	use rbtd::rbtdri_invocation::{rbtdri_Context, rbtdri_invoke_global};
40	use rbtd::rbtdrm_manifest::{rbtdrm_verify, RBTDRM_COLOPHON_CRUCIBLE_ACTIVE};
41	
42	fn main() -> ExitCode {
43	    let args: Vec<String> = std::env::args().collect();
44	
45	    if args.get(1).map(|s| s.as_str()) == Some("single") {
46	        return rbtdb_run_single(&args[2..]);
47	    }
48	
49	    rbtdb_run_suite(&args[1..])
50	}
51	
52	fn rbtdb_read_dispatch_dir(name: &str) -> Result<PathBuf, String> {
53	    match std::env::var(name) {
54	        Ok(v) if !v.is_empty() => Ok(PathBuf::from(v)),
55	        _ => Err(format!(
56	            "rbtd: {} is not set — theurge must be launched via BUK tabtarget",
57	            name
58	        )),
59	    }
60	}
61	
62	struct rbtdb_Roots {
63	    trace_root: PathBuf,
64	    burv_temp_root: PathBuf,
65	    burv_output_root: PathBuf,
66	}
67	
68	fn rbtdb_allocate_roots() -> Result<rbtdb_Roots, String> {
69	    let burd_temp = rbtdb_read_dispatch_dir("BURD_TEMP_DIR")?;
70	    let burd_output = rbtdb_read_dispatch_dir("BURD_OUTPUT_DIR")?;
71	
72	    let trace_root = burd_temp.join("rbtd");
73	    let burv_temp_root = trace_root.join("burv");
74	    let burv_output_root = burd_output.join("rbtd").join("burv");
75	
76	    std::fs::create_dir_all(&trace_root)
77	        .map_err(|e| format!("rbtd: failed to create trace root '{}': {}", trace_root.display(), e))?;
78	    std::fs::create_dir_all(&burv_temp_root)
79	        .map_err(|e| format!("rbtd: failed to create burv temp root '{}': {}", burv_temp_root.display(), e))?;
80	    std::fs::create_dir_all(&burv_output_root)
81	        .map_err(|e| format!("rbtd: failed to create burv output root '{}': {}", burv_output_root.display(), e))?;
82	
83	    Ok(rbtdb_Roots { trace_root, burv_temp_root, burv_output_root })
84	}
85	
86	// ── Suite runner ─────────────────────────────────────────────
87	
88	fn rbtdb_run_suite(args: &[String]) -> ExitCode {
89	    let manifest = match args.first() {
90	        Some(m) => m,
91	        None => {
92	            eprintln!(
93	                "rbtd: usage: rbtd <manifest> <fixture>\n\
94	                 theurge must be launched via tabtarget (e.g. tt/rbtd-r.FixtureRun.tadmor.sh)"
95	            );
96	            return ExitCode::FAILURE;
97	        }
98	    };
99	
100	    let fixture = match args.get(1) {
101	        Some(n) => n,
102	        None => {
103	            eprintln!("rbtd: no fixture argument — which test fixture to run?");
104	            return ExitCode::FAILURE;
105	        }
106	    };
107	
108	    if let Err(msg) = rbtdrm_verify(manifest, fixture) {
109	        eprintln!("{}", msg);
110	        return ExitCode::FAILURE;
111	    }
112	
113	    let project_root = match std::env::current_dir() {
114	        Ok(p) => p,
115	        Err(e) => {
116	            eprintln!("rbtd: cannot determine working directory: {}", e);
117	            return ExitCode::FAILURE;
118	        }
119	    };
120	
121	    let roots = match rbtdb_allocate_roots() {
122	        Ok(r) => r,
123	        Err(msg) => {
124	            eprintln!("{}", msg);
125	            return ExitCode::FAILURE;
126	        }
127	    };
128	
129	    let ctx = rbtdri_Context::new(
130	        &project_root,
131	        fixture,
132	        &roots.burv_temp_root,
133	        &roots.burv_output_root,
134	    );
135	
136	    let fixture_def = match rbtdrc_lookup_fixture(fixture) {
137	        Some(f) => f,
138	        None => {
139	            eprintln!(
140	                "rbtd: fixture '{}' has no registered Fixture — \
141	                 manifest verification accepted the name but no Fixture static is bound. \
142	                 Update rbtdrc_lookup_fixture in rbtdrc_crucible.rs.",
143	                fixture
144	            );
145	            return ExitCode::FAILURE;
146	        }
147	    };
148	
149	    rbtdrc_set_context(ctx);
150	
151	    let colors = rbtdre_detect_colors();
152	    let run_result = rbtdre_run_fixture(fixture_def, &colors, &roots.trace_root);
153	
154	    let _ctx = rbtdrc_take_context();
155	
156	    let result = match run_result {
157	        Ok(r) => r,
158	        Err(msg) => {
159	            eprintln!("rbtd: {}", msg);
160	            return ExitCode::FAILURE;
161	        }
162	    };
163	
164	    rbtdre_print_summary(&result, &colors);
165	
166	    if result.failed > 0 {
167	        eprintln!("rbtd: {} case(s) failed", result.failed);
168	        ExitCode::FAILURE
169	    } else {
170	        ExitCode::SUCCESS
171	    }
172	}
173	
174	// ── Single-case runner ───────────────────────────────────────
175	
176	fn rbtdb_run_single(args: &[String]) -> ExitCode {
177	    let manifest = match args.first() {
178	        Some(m) => m,
179	        None => {
180	            eprintln!(
181	                "rbtd single: usage: rbtd single <manifest> <fixture> [case]\n\
182	                 omit case to list all cases for the fixture"
183	            );
184	            return ExitCode::FAILURE;
185	        }
186	    };
187	
188	    let fixture = match args.get(1) {
189	        Some(f) => f,
190	        None => {
191	            eprintln!("rbtd single: no fixture argument");
192	            rbtdb_list_fixtures();
193	            return ExitCode::FAILURE;
194	        }
195	    };
196	
197	    if !RBTDRC_FIXTURES.iter().any(|f| f.name == *fixture) {
198	        eprintln!("rbtd single: unknown fixture '{}'", fixture);
199	        rbtdb_list_fixtures();
200	        return ExitCode::FAILURE;
201	    }
202	
203	    if let Err(msg) = rbtdrm_verify(manifest, fixture) {
204	        eprintln!("{}", msg);
205	        return ExitCode::FAILURE;
206	    }
207	
208	    // Set up execution context early — needed for charge check and case execution
209	    let project_root = match std::env::current_dir() {
210	        Ok(p) => p,
211	        Err(e) => {
212	            eprintln!("rbtd: cannot determine working directory: {}", e);
213	            return ExitCode::FAILURE;
214	        }
215	    };
216	
217	    let roots = match rbtdb_allocate_roots() {
218	        Ok(r) => r,
219	        Err(msg) => {
220	            eprintln!("{}", msg);
221	            return ExitCode::FAILURE;
222	        }
223	    };
224	
225	    // Context is required for every case execution path (rbtdrc_with_ctx).
226	    // Fixtures with a setup hook (crucible charge) additionally verify their
227	    // crucible is charged externally — single-case mode never charges.
228	    let mut ctx = rbtdri_Context::new(
229	        &project_root,
230	        fixture,
231	        &roots.burv_temp_root,
232	        &roots.burv_output_root,
233	    );
234	
235	    let fixture_def = match rbtdrc_lookup_fixture(fixture) {
236	        Some(f) => f,
237	        None => {
238	            eprintln!(
239	                "rbtd single: fixture '{}' has no registered Fixture",
240	                fixture
241	            );
242	            return ExitCode::FAILURE;
243	        }
244	    };
245	
246	    if fixture_def.setup.is_some() {
247	        match rbtdri_invoke_global(
248	            &mut ctx,
249	            RBTDRM_COLOPHON_CRUCIBLE_ACTIVE,
250	            &[fixture],
251	            &[],
252	        ) {
253	            Ok(r) if r.exit_code == 0 => {}
254	            _ => {
255	                eprintln!(
256	                    "rbtd single: crucible not charged for '{}'\n\
257	                     charge first: tt/rbw-cC.Charge.{}.sh",
258	                    fixture, fixture
259	                );
260	                return ExitCode::FAILURE;
261	            }
262	        }
263	    }
264	
265	    rbtdrc_set_context(ctx);
266	
267	    let cases = fixture_def.cases;
268	
269	    // No case argument — list all cases
270	    let case_name = match args.get(2) {
271	        None => {
272	            rbtdre_list_cases(cases);
273	            return ExitCode::SUCCESS;
274	        }
275	        Some(n) => n,
276	    };
277	
278	    // Find the case
279	    let case = match rbtdre_find_case(cases, case_name) {
280	        Some(c) => c,
281	        None => {
282	            eprintln!(
283	                "rbtd single: case '{}' not found in fixture '{}'",
284	                case_name, fixture
285	            );
286	            rbtdre_list_cases(cases);
287	            return ExitCode::FAILURE;
288	        }
289	    };
290	
291	    let colors = rbtdre_detect_colors();
292	    let result = match rbtdre_run_single_case(case, &colors, &roots.trace_root) {
293	        Ok(r) => r,
294	        Err(msg) => {
295	            eprintln!("rbtd: case execution error: {}", msg);
296	            return ExitCode::FAILURE;
297	        }
298	    };
299	
300	    rbtdre_print_summary(&result, &colors);
301	
302	    if result.failed > 0 {
303	        ExitCode::FAILURE
304	    } else {
305	        ExitCode::SUCCESS
306	    }
307	}
308	
309	fn rbtdb_list_fixtures() {
310	    eprintln!("available fixtures:");
311	    for f in RBTDRC_FIXTURES {
312	        eprintln!("  {}", f.name);
313	    }
314	}
