//
// RBTDRG — output module per RCG Output Discipline.
//
// All theurge emissions route through these macros. Output goes to stderr,
// matching theurge's prior eprintln!-everywhere pattern; stdout stays
// reserved for tabtarget bypass (none today, but the channel is intact).
//
// Format: `[LEVEL] [file:line] message`
//
// Suffix families implemented: `_now` only. The 42 existing emission sites
// are all unconditional; `_if` and comparison variants can be added as
// callers grow a need for them.

use std::io::Write;

pub const RBTDRG_LEVEL_TRACE: &str = "[TRACE]";
pub const RBTDRG_LEVEL_INFO:  &str = "[INFO]";
pub const RBTDRG_LEVEL_ERROR: &str = "[ERROR]";
pub const RBTDRG_LEVEL_FATAL: &str = "[FATAL]";

#[doc(hidden)]
pub fn zrbtdrg_emit(level: &str, file: &str, line: u32, msg: &str) {
    let mut stderr = std::io::stderr().lock();
    let _ = writeln!(stderr, "{} [{}:{}] {}", level, file, line, msg);
}

#[doc(hidden)]
pub fn zrbtdrg_emit_fatal(file: &str, line: u32, msg: &str) -> ! {
    let mut stderr = std::io::stderr().lock();
    let _ = writeln!(stderr, "{} [{}:{}] {}", RBTDRG_LEVEL_FATAL, file, line, msg);
    let _ = stderr.flush();
    std::process::exit(1);
}

#[macro_export]
macro_rules! rbtdrg_trace_now {
    ($($arg:tt)*) => {
        $crate::rbtdrg_log::zrbtdrg_emit(
            $crate::rbtdrg_log::RBTDRG_LEVEL_TRACE,
            file!(), line!(),
            &format!($($arg)*),
        )
    };
}

#[macro_export]
macro_rules! rbtdrg_info_now {
    ($($arg:tt)*) => {
        $crate::rbtdrg_log::zrbtdrg_emit(
            $crate::rbtdrg_log::RBTDRG_LEVEL_INFO,
            file!(), line!(),
            &format!($($arg)*),
        )
    };
}

#[macro_export]
macro_rules! rbtdrg_error_now {
    ($($arg:tt)*) => {
        $crate::rbtdrg_log::zrbtdrg_emit(
            $crate::rbtdrg_log::RBTDRG_LEVEL_ERROR,
            file!(), line!(),
            &format!($($arg)*),
        )
    };
}

#[macro_export]
macro_rules! rbtdrg_fatal_now {
    ($($arg:tt)*) => {
        $crate::rbtdrg_log::zrbtdrg_emit_fatal(
            file!(), line!(),
            &format!($($arg)*),
        )
    };
}

