    match std::env::var("BURD_TEMP_DIR") {
        Ok(v) if !v.is_empty() => PathBuf::from(v),
        _ => panic!(
            "rbtdth: BURD_TEMP_DIR is not set — run tests via `tt/rbtd-t.Test.sh`"
        ),
    }
}

