91	/// driven by the per-nameplate `RBRN_BOTTLE_READINESS_DELAY_SEC` fact.
92	pub fn rbtdrc_charge_crucible() -> Result<(), String> {
93	    RBTDRC_CTX.with(|c| {
94	        let mut opt = c.borrow_mut();
95	        let ctx = opt
96	            .as_mut()
97	            .ok_or_else(|| "rbtdrc: no invocation context for charge".to_string())?;
98	        zrbtdrc_charge_impl(ctx)
99	    })
